// --- FUNZIONI DI SUPPORTO (RUMORE) ---

// Funzione Hash semplice per generare pseudocasualità
float random (in vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
}

// Noise semplice (interpolazione di valori casuali)
float noise (in vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Smoothstep standard (rende le curve morbide)
    // Formula: t * t * (3.0 - 2.0 * t)
    vec2 u = f * f * (3.0 - 2.0 * f);

    return mix(mix(random(i + vec2(0.0,0.0)), 
                   random(i + vec2(1.0,0.0)), u.x),
               mix(random(i + vec2(0.0,1.0)), 
                   random(i + vec2(1.0,1.0)), u.x), u.y);
}

// FBM (Fractal Brownian Motion)
// Somma diversi strati di rumore per creare dettaglio
#define OCTAVES 6
float fbm (in vec2 st) {
    float value = 0.0;
    float amplitude = .5;
    float frequency = 0.;

    // Loop per aggiungere dettagli sempre più fini
    for (int i = 0; i < OCTAVES; i++) {
        value += amplitude * noise(st);
        st *= 2.;
        amplitude *= .5;
    }
    return value;
}

// --- MAIN SHADER ---

void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Normalizziamo le coordinate (da 0 a 1)
    vec2 st = fragCoord.xy/iResolution.xy;
    st.x *= iResolution.x/iResolution.y; // Correzione aspect ratio

    // DOMAIN WARPING
    // Qui avviene la magia. Spostiamo 'st' usando il tempo e il rumore.

    vec2 q = vec2(0.);
    q.x = fbm( st + 0.00*iTime);
    q.y = fbm( st + vec2(1.0));

    vec2 r = vec2(0.);
    r.x = fbm( st + 1.0*q + vec2(1.7,9.2)+ 0.15*iTime );
    r.y = fbm( st + 1.0*q + vec2(8.3,2.8)+ 0.126*iTime);

    // Il valore finale 'f' è il rumore calcolato sulle coordinate distorte 'r'
    float f = fbm(st + r);

    // --- COLORAZIONE ---

    // Mescoliamo i colori in base al valore 'f' risultante.
    // Colore 1 (Scuro/Base)
    vec3 color = mix(vec3(0.101961,0.619608,0.666667),
                     vec3(0.666667,0.666667,0.498039),
                     clamp((f*f)*4.0,0.0,1.0));

    // Colore 2 (Chiaro/Highlight)
    color = mix(color,
                vec3(0,0,0.164706),
                clamp(length(q),0.0,1.0));

    // Colore 3 (Dettagli finali)
    color = mix(color,
                vec3(0.666667,1,1),
                clamp(length(r.x),0.0,1.0));

    // Output finale su schermo
    fragColor = vec4((f*f*f+.6*f*f+.5*f)*color,1.);
}

