// Adattamento per Desktop GLSL Audio
// Rimosse le dipendenze da iChannel0 (texture Shadertoy) in favore di 
// funzioni hash puramente matematiche per la compatibilità con il custom synth.
// =========================================================================

vec3 CameraPath( float t )
{
    float s = smoothstep(0.0, 3.0, t);
    vec3 pos = vec3( t*30.0*s +120.0, 1.0, t* 220.0* s -80.0);

    float a = t/4.0;
    pos.xz += vec2(1350.0 * cos(a), 350.0*sin(a));
    pos.xz += vec2(1400.0 * sin(-a*1.8), 400.0*cos(-a*4.43));

    return pos;
}

// -------------------------------------------------------------------------
// NUOVO HASH MATEMATICO: Sostituisce la lettura da iChannel0
vec2 Hash(vec2 p) 
{
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453123);
}

//--------------------------------------------------------------------------
vec2 Noise( in vec2 x )
{
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f*f*(3.0-2.0*f);

    // Ora utilizza la funzione Hash matematica definita sopra
    vec2 res = mix(mix( Hash(p + 0.0), Hash(p + vec2(1.0, 0.0)), f.x),
                   mix( Hash(p + vec2(0.0, 1.0) ), Hash(p + vec2(1.0, 1.0)), f.x), f.y);
    return res - 0.5;
}

//--------------------------------------------------------------------------
vec2 FBM( vec2 p )
{
    vec2 f;
    f  = 0.50000 * Noise(p); p = p * 2.32;
    f += 0.25000 * Noise(p); p = p * 2.23;
    f += 0.12500 * Noise(p); p = p * 2.31;
    f += 0.06250 * Noise(p); p = p * 2.28;
    f += 0.03125 * Noise(p);
    return f;
}

//--------------------------------------------------------------------------
// Funzione extra adattata anch'essa senza texture (anche se non usata sotto)
float rockets(float t)
{
    vec2 h1 = Hash(vec2(t*0.3, t*0.1731));
    vec2 h2 = Hash(vec2(t*0.2, t*0.01731));
    return (h1.x - 0.5) + (h2.y - 0.5);
}

//--------------------------------------------------------------------------
vec2 mainSound( in int samp, float time )
{
    float gTime = (time + 135.0) * 0.25;
    vec3 ca = CameraPath(gTime);
    vec3 ct = CameraPath(gTime + 0.05);
    float f = length(ct - ca) * 0.1;

    vec2 audio;
    audio = FBM(vec2(gTime * 120.0, gTime * 1200.0)) * 5.0 * f;
    audio += FBM(vec2(gTime * 200.0 * f, gTime * 200.0)) * 4.5;
    audio *= 0.1;

    // float g = mod(f*gTime, 8.0);
    // audio *= g < 4.0 ? 1.0 : 0.0;

    // Applica fade-in e fade-out
    return audio * smoothstep(0.0, 2.0, time) * smoothstep(180.0, 170.0, time);
}
