// Imposta lo zoom/scala iniziale
vec2 z = (uv - 0.5) * 3.0; 

// Costante complessa C (Modifica questi valori per cambiare la forma!)
// Valori interessanti: 
// vec2(-0.7, 0.27015)
// vec2(0.285, 0.01)
// vec2(-0.8, 0.156)
vec2 c = vec2(0.285, 0.01); 

int iter = 0;
int maxIter = 100;

// Iterazione Julia standard: Z = Z^2 + C
for(iter = 0; iter < maxIter; iter++) {
    float x = (z.x * z.x - z.y * z.y) + c.x;
    float y = (2.0 * z.x * z.y) + c.y;
    z = vec2(x, y);

    // Se esce dal raggio 2 (distanza quadrata 4), è fuori dall'insieme
    if (dot(z, z) > 4.0) break;
}

// Colorazione
if (iter == maxIter) {
    // Interno dell'insieme: un colore scuro ma morbido (es. indaco scuro)
    return vec3(0.2, 0.15, 0.3); 
} else {
    // Esterno: Gradiente Pastello
    float t = float(iter) / 20.0; // Divisore più basso = bande più fitte

    // Generazione colori base (Ciclo RGB morbido)
    float r = 0.5 + 0.5 * cos(t + 0.0);
    float g = 0.5 + 0.5 * cos(t + 2.09); // 2.09 è circa 2*PI/3
    float b = 0.5 + 0.5 * cos(t + 4.18); // 4.18 è circa 4*PI/3

    vec3 color = vec3(r, g, b);

    // TRUCCO PASTELLO: 
    // Mixiamo il colore con il bianco (vec3(1.0)) al 50%
    return mix(color, vec3(1.0), 0.5);
}
